# ─── Seeding function ─────────────────────────────────────────────────────────

def sb_request(method, path, data=None):
    url = f"{SUPABASE_URL}/rest/v1/{path}"
    headers = {
        "apikey": SUPABASE_KEY,
        "Authorization": f"Bearer {SUPABASE_KEY}",
        "Content-Type": "application/json",
        "Prefer": "return=minimal",
    }
    body = json.dumps(data).encode() if data else None
    req = urllib.request.Request(url, data=body, headers=headers, method=method)
    try:
        with urllib.request.urlopen(req) as resp:
            return resp.status, resp.read().decode()
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode()

def seed():
    if not SUPABASE_KEY:
        print("❌  Set SUPABASE_SERVICE_KEY env var before running.")
        return

    print(f"🚀  Seeding {len(PUZZLES)} puzzles across 8 class levels...\n")

    batch_size = 50
    batches = [PUZZLES[i:i+batch_size] for i in range(0, len(PUZZLES), batch_size)]

    total_ok = 0
    for idx, batch in enumerate(batches):
        rows = []
        for p in batch:
            rows.append({
                "class_num":   p[0],
                "seq_num":     p[1],
                "title":       p[2],
                "description": p[3],
                "answer":      p[4],
                "hint":        p[5],
                "puzzle_type": p[6],
                "xp_reward":   p[7],
                "coin_reward": p[8],
            })
        status, body = sb_request("POST", f"{TABLE}?on_conflict=class_num,seq_num", rows)
        if status in (200, 201):
            total_ok += len(rows)
            print(f"  ✅  Batch {idx+1}/{len(batches)} — {len(rows)} rows inserted (total: {total_ok})")
        else:
            print(f"  ❌  Batch {idx+1} failed — HTTP {status}: {body[:300]}")

    print(f"\n{'✅' if total_ok == len(PUZZLES) else '⚠️ '}  Done. {total_ok}/{len(PUZZLES)} puzzles seeded.")
    if total_ok != len(PUZZLES):
        print("   Some batches failed. Re-run to retry — on_conflict=class_num,seq_num handles duplicates safely.")

if __name__ == "__main__":
    seed()
